patch:
--- a/comparator_64bit.vhd
+++ b/comparator_64bit.vhd
@@ -1,15 +1,15 @@
 library ieee;
 use ieee.std_logic_1164.all;

 entity comparator_64bit is
   port (
     val_a : in std_logic_vector(63 downto 0);
     val_b : in std_logic_vector(63 downto 0);
     eq_flag : out std_logic
   );
 end entity;

 architecture rtl of comparator_64bit is
 begin
-  process(val_a)
+  process(val_a, val_b)
   begin
     if (val_a = val_b) then
       eq_flag <= '1';
     else
       eq_flag <= '0';
     end if;
   end process;

 end architecture;

